package com.example.nofiltercoffee; import android.content.*; import android.os.*; import android.view.*; import android.widget.*; import androidx.appcompat.app.*;
public class SignupActivity extends AppCompatActivity{EditText n,e,ph,p,c;TextView err;protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_signup);n=findViewById(R.id.edtName);e=findViewById(R.id.edtEmail);ph=findViewById(R.id.edtPhone);p=findViewById(R.id.edtPassword);c=findViewById(R.id.edtConfirmPassword);err=findViewById(R.id.txtError);findViewById(R.id.btnSignup).setOnClickListener(v->signup());findViewById(R.id.btnGoLogin).setOnClickListener(v->{startActivity(new Intent(this,LoginActivity.class));finish();});} void signup(){String name=n.getText().toString().trim(), email=e.getText().toString().trim(), phone=ph.getText().toString().trim(), pw=p.getText().toString(), cp=c.getText().toString(); if(name.length()<3){show("Enter your full name.");return;} if(!email.contains("@")||!email.contains(".")){show("Enter a valid email.");return;} if(phone.length()<10){show("Enter a valid phone number.");return;} if(pw.length()<6){show("Password must be at least 6 characters.");return;} if(!pw.equals(cp)){show("Passwords do not match.");return;} UserSession.createAccount(this,name,email,phone,pw);startActivity(new Intent(this,HomeActivity.class).setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP|Intent.FLAG_ACTIVITY_NEW_TASK));finish();} void show(String s){err.setText(s);err.setVisibility(View.VISIBLE);}}
